package terminal

import (
	"context"
	"encoding/binary"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"sync"
)

const (
	pipeFrameHeaderBytes = 5
	pipeMaxPayloadBytes  = 16 * 1024 * 1024

	pipeMsgTerminalData  byte = 0x01
	pipeMsgTerminalInput byte = 0x02
	pipeMsgResize        byte = 0x03
	pipeMsgStatus        byte = 0x07
)

type pipeConnector func(context.Context, string) (io.ReadWriteCloser, error)

func startPipeProcess(ctx context.Context, pipePath string) (Process, error) {
	conn, err := dialPipe(ctx, pipePath)
	if err != nil {
		return nil, err
	}

	return newPipeProcess(conn), nil
}

func newPipeProcess(conn io.ReadWriteCloser) *pipeProcess {
	return &pipeProcess{
		conn: conn,
		done: make(chan struct{}),
	}
}

type pipeProcess struct {
	conn    io.ReadWriteCloser
	done    chan struct{}
	exitErr error
	once    sync.Once
	pending []byte
	writeMu sync.Mutex
}

func (p *pipeProcess) Read(buf []byte) (int, error) {
	if len(p.pending) > 0 {
		n := copy(buf, p.pending)
		p.pending = p.pending[n:]
		return n, nil
	}

	for {
		messageType, payload, err := readPipeFrame(p.conn)
		if err != nil {
			if errors.Is(err, io.EOF) {
				p.finish(nil)
			} else {
				p.finish(err)
			}
			return 0, err
		}

		switch messageType {
		case pipeMsgTerminalData:
			p.pending = payload
			return p.Read(buf)
		case pipeMsgStatus:
			if !pipeStatusAlive(payload) {
				p.finish(nil)
				return 0, io.EOF
			}
		}
	}
}

func (p *pipeProcess) Write(buf []byte) (int, error) {
	if err := p.writeFrame(pipeMsgTerminalInput, buf); err != nil {
		return 0, err
	}

	return len(buf), nil
}

func (p *pipeProcess) Close() error {
	err := p.conn.Close()
	p.finish(nil)
	return err
}

func (p *pipeProcess) Resize(cols int, rows int) error {
	payload, err := json.Marshal(map[string]int{
		"cols": cols,
		"rows": rows,
	})
	if err != nil {
		return err
	}

	return p.writeFrame(pipeMsgResize, payload)
}

func (p *pipeProcess) Wait() error {
	<-p.done
	return p.exitErr
}

func (p *pipeProcess) writeFrame(messageType byte, payload []byte) error {
	p.writeMu.Lock()
	defer p.writeMu.Unlock()

	frame := make([]byte, pipeFrameHeaderBytes+len(payload))
	frame[0] = messageType
	binary.BigEndian.PutUint32(frame[1:pipeFrameHeaderBytes], uint32(len(payload)))
	copy(frame[pipeFrameHeaderBytes:], payload)
	err := writeFull(p.conn, frame)
	if err != nil {
		p.finish(err)
	}

	return err
}

func (p *pipeProcess) finish(err error) {
	p.once.Do(func() {
		p.exitErr = err
		close(p.done)
	})
}

func readPipeFrame(reader io.Reader) (byte, []byte, error) {
	header := make([]byte, pipeFrameHeaderBytes)
	if _, err := io.ReadFull(reader, header); err != nil {
		return 0, nil, err
	}

	payloadLength := binary.BigEndian.Uint32(header[1:pipeFrameHeaderBytes])
	if payloadLength > pipeMaxPayloadBytes {
		return 0, nil, fmt.Errorf("pipe payload too large: %d bytes", payloadLength)
	}

	payload := make([]byte, payloadLength)
	if _, err := io.ReadFull(reader, payload); err != nil {
		return 0, nil, err
	}

	return header[0], payload, nil
}

func writeFull(writer io.Writer, payload []byte) error {
	for len(payload) > 0 {
		n, err := writer.Write(payload)
		if err != nil {
			return err
		}
		if n == 0 {
			return io.ErrShortWrite
		}
		payload = payload[n:]
	}

	return nil
}

func pipeStatusAlive(payload []byte) bool {
	var status struct {
		Alive bool `json:"alive"`
	}
	if err := json.Unmarshal(payload, &status); err != nil {
		return true
	}

	return status.Alive
}

