   193	func TestWorkspaceProviderIgnoresNonZellijRuntimeForTerminalAttach(t *testing.T) {
   194		baseDir := t.TempDir()
   195		writeFile(t, filepath.Join(baseDir, runningFileName), `{
   196	  "projects": ["ao-legacy_abc123"]
   197	}`)
   198		sessionsDir := filepath.Join(baseDir, "projects", "ao-legacy_abc123", "sessions")
   199		writeFile(t, filepath.Join(sessionsDir, "legacy-1.json"), `{
   200	  "agent": "codex",
   201	  "branch": "feature/legacy-runtime",
   202	  "status": "working",
   203	  "worktree": "/tmp/legacy-1",
   204	  "lifecycle": {
   205	    "session": {"kind": "worker", "state": "working"},
   206	    "runtime": {
   207	      "state": "alive",
   208	      "handle": {
   209	        "id": "legacy-1",
   210	        "runtimeName": "process",
   211	        "data": {
   212	          "workspacePath": "/tmp/legacy-1"
   213	        }
   214	      }
   215	    }
   216	  }
   217	}`)
   218	
   219		provider := WorkspaceProvider{BaseDir: baseDir}
   220		workspace, err := provider.Workspace(context.Background())
   221		if err != nil {
   222			t.Fatalf("workspace: %v", err)
   223		}
   224		if len(workspace.Sessions) != 1 {
   225			t.Fatalf("expected one worker session, got %#v", workspace.Sessions)
   226		}
   227	
   228		worker := workspace.Sessions[0]
   229		if worker.TerminalSupported {
   230			t.Fatal("expected non-zellij worker not to support terminals")
   231		}
   232		if len(worker.AttachCommand) != 0 {
   233			t.Fatalf("non-zellij worker should not use attach command: %#v", worker.AttachCommand)
   234		}
   235		if worker.ZellijSession != "" {
   236			t.Fatalf("non-zellij worker should not expose a zellij session, got %q", worker.ZellijSession)
   237		}
   238	}
