   240	func writeFile(t *testing.T, path string, content string) {
   241		t.Helper()
   242	
   243		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
   244			t.Fatalf("mkdir: %v", err)
   245		}
   246		if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
   247			t.Fatalf("write file: %v", err)
   248		}
